import React from "react";
import { useTranslation } from "react-i18next";
import { List, Card, Typography, Tag, Space, DatePicker, Button, theme } from "antd";
import { MedicineBoxOutlined, ArrowRightOutlined, FilePdfOutlined } from "@ant-design/icons";

const { Title, Text } = Typography;

const TransportLogPage: React.FC = () => {
  const { t } = useTranslation(["quarantine"]);
  const { token } = theme.useToken();

  const transportData = [
    { id: "T-2026-001", time: "10:25", from: "Gate G12", to: "Isolution Ward A", status: "completed", patient: "P-8821" },
    { id: "T-2026-002", time: "11:10", from: "Gate G05", to: "Local Hospital", status: "in-progress", patient: "P-8825" },
    { id: "T-2026-003", time: "11:45", from: "Gate G12", to: "Isolution Ward B", status: "pending", patient: "P-8830" },
  ];

  return (
    <div className="p-6 h-full flex flex-col" style={{ background: token.colorBgLayout }}>
      <div className="flex justify-between items-center mb-6">
        <Title level={4} style={{ margin: 0, color: token.colorText, fontWeight: "bold" }}>
          {t("navigation:transportLog")}
        </Title>
        <Space>
          <DatePicker.RangePicker style={{ background: token.colorBgContainer, height: 40, borderRadius: 8 }} />
          <Button 
            style={{ background: token.colorPrimary, color: token.colorTextLightSolid, fontWeight: "bold", height: 40, padding: "0 24px" }}
            icon={<FilePdfOutlined />}
          >
            REPORT
          </Button>
        </Space>
      </div>

      <Card 
        bordered={false} 
        className="shadow-sm flex-1 overflow-hidden" 
        style={{ background: token.colorBgContainer, borderRadius: 16 }}
        styles={{ body: { padding: 0 } }}
      >
        <div className="flex flex-col h-full overflow-y-auto custom-list">
           {transportData.map((item, idx) => (
             <div 
               key={item.id}
               className="px-6 py-5 flex items-center justify-between transition-colors border-b hover-bg"
               style={{ borderColor: token.colorBorderSecondary }}
             >
                <div className="flex items-center gap-4 flex-1">
                   <div className="p-4 rounded-xl flex items-center justify-center shadow-sm" style={{ background: `${token.colorError}1A` }}>
                     <MedicineBoxOutlined style={{ color: token.colorError, fontSize: 24 }} />
                   </div>
                   <div>
                     <Text className="block" style={{ color: token.colorText, fontWeight: "bold", fontSize: 15 }}>{item.id}</Text>
                     <Text style={{ color: token.colorTextDescription, fontSize: 13 }}>{item.time} | {t("history:patientID")}: {item.patient}</Text>
                   </div>
                </div>

                <div className="flex items-center gap-10 pr-10">
                   <div className="text-right">
                      <div style={{ color: token.colorTextQuaternary, fontSize: 12, marginBottom: 4, fontWeight: "bold", textTransform: "uppercase" }}>{t("history:departure")}</div>
                      <Tag style={{ background: `${token.colorPrimary}26`, borderColor: `${token.colorPrimary}40`, color: token.colorPrimary, fontWeight: "bold", fontSize: 13, padding: "2px 12px", borderRadius: 4 }}>{item.from}</Tag>
                   </div>
                   <ArrowRightOutlined style={{ color: token.colorTextQuaternary, fontSize: 20 }} />
                   <div className="text-left">
                      <div style={{ color: token.colorTextQuaternary, fontSize: 12, marginBottom: 4, fontWeight: "bold", textTransform: "uppercase" }}>{t("history:destination")}</div>
                      <Tag style={{ background: `${token.colorWarning}26`, borderColor: `${token.colorWarning}40`, color: token.colorWarning, fontWeight: "bold", fontSize: 13, padding: "2px 12px", borderRadius: 4 }}>{item.to}</Tag>
                   </div>
                   <div className="ml-10 min-w-[100px] text-center">
                      {(() => {
                         const statusColor = item.status === "completed" ? token.colorSuccess : item.status === "in-progress" ? token.colorPrimary : token.colorTextQuaternary;
                         return (
                           <Tag style={{ background: `${statusColor}26`, borderColor: `${statusColor}40`, color: statusColor, fontWeight: "bold", fontSize: 12, padding: "2px 12px", borderRadius: 4, textTransform: "uppercase" }}>
                             {t(`common:${item.status.replace("-", "P").replace("in-progress", "inProgress")}`)}
                           </Tag>
                         );
                      })()}
                   </div>
                </div>

                <div className="flex items-center gap-2">
                   <Button type="link" style={{ fontWeight: "bold" }}>{t("common:detail")}</Button>
                   <Button type="link" style={{ fontWeight: "bold", color: token.colorInfo }}>GPS TRACE</Button>
                </div>
             </div>
           ))}
        </div>
      </Card>

      <style>{`
        .custom-list .ant-list-item:hover { background: ${token.colorFillAlter} !important; }
        .ant-picker-range .ant-picker-input > input { color: ${token.colorText} !important; }
      `}</style>
    </div>
  );
};

export default TransportLogPage;
